using System.CommandLine;
using System.CommandLine.Invocation;
using System.CommandLine.Parsing;

var rootCommand = new RootCommand("Compares two BenchmarkDotNet results and reports performance regressions.");

var baselineOption = new Option<FileInfo>("--baseline", "The baseline BenchmarkDotNet results file.") { IsRequired = true };
var candidateOption = new Option<FileInfo>("--candidate", "The candidate BenchmarkDotNet results file.") { IsRequired = true };
var thresholdOption = new Option<double>("--threshold", () => 10.0, "The regression threshold percentage.");
var outputOption = new Option<FileInfo?>("--output", "The output file to write the results to.");

rootCommand.AddOption(baselineOption);
rootCommand.AddOption(candidateOption);
rootCommand.AddOption(thresholdOption);
rootCommand.AddOption(outputOption);

rootCommand.SetHandler(async (InvocationContext context) =>
{
    var baseline = context.ParseResult.GetValueForOption(baselineOption)!;
    var candidate = context.ParseResult.GetValueForOption(candidateOption)!;
    var threshold = context.ParseResult.GetValueForOption(thresholdOption);
    var output = context.ParseResult.GetValueForOption(outputOption);
    var cancellationToken = context.GetCancellationToken();

    var options = new PerfDiffOptions(baseline, candidate, threshold, output);
    context.ExitCode = await PerfDiff.RunAsync(options, cancellationToken);
});

return await rootCommand.InvokeAsync(args);
